import { Card, Stack, Row, Text } from '@ggui-ai/design/primitives';

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: Array<{ day: string; icon: string; high: number; low: number }>;
}

const getWeatherEmoji = (condition: string): string => {
  const lower = condition.toLowerCase();
  if (lower.includes('sunny') || lower.includes('clear')) return '☀️';
  if (lower.includes('cloudy') || lower.includes('cloud')) return '☁️';
  if (lower.includes('rainy') || lower.includes('rain')) return '🌧️';
  if (lower.includes('snow')) return '❄️';
  if (lower.includes('storm') || lower.includes('thunder')) return '⛈️';
  if (lower.includes('wind')) return '💨';
  return '🌤️';
};

export default function GeneratedComponent(props: Props) {
  const { city, temperature, condition, humidity, windSpeed, unit, forecast } = props;

  return (
    <Card
      padding="24"
      shadow="md"
      style={{
        background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
      }}
    >
      <Stack direction="vertical" gap={24}>
        {/* Header with City */}
        <div style={{ textAlign: 'center' }}>
          <Text variant="h2" style={{ color: 'var(--ggui-color-onSurface, #18181b)' }}>
            {city}
          </Text>
        </div>

        {/* Current Weather Section */}
        <Stack direction="vertical" gap={16} align="center">
          {/* Temperature - Large and Prominent */}
          <div style={{ textAlign: 'center' }}>
            <Text
              style={{
                fontSize: 'var(--ggui-font-size-4xl, 36px)',
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
                color: 'var(--ggui-color-onSurface, #18181b)',
                lineHeight: '1.2',
              }}
            >
              {temperature}°{unit}
            </Text>
          </div>

          {/* Condition with Icon/Emoji */}
          <div style={{ textAlign: 'center' }}>
            <div
              style={{
                fontSize: '48px',
                marginBottom: 'var(--ggui-spacing-2, 8px)',
              }}
            >
              {getWeatherEmoji(condition)}
            </div>
            <Text
              variant="body"
              style={{
                color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                fontSize: 'var(--ggui-font-size-lg, 18px)',
              }}
            >
              {condition}
            </Text>
          </div>
        </Stack>

        {/* Humidity and Wind Speed */}
        <Row gap={32} justify="center">
          {/* Humidity */}
          <Stack direction="vertical" gap={8} align="center">
            <div style={{ fontSize: '28px' }}>💧</div>
            <Text
              style={{
                color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                fontSize: 'var(--ggui-font-size-sm, 14px)',
              }}
            >
              Humidity
            </Text>
            <Text
              style={{
                color: 'var(--ggui-color-onSurface, #18181b)',
                fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                fontSize: 'var(--ggui-font-size-lg, 18px)',
              }}
            >
              {humidity}%
            </Text>
          </Stack>

          {/* Wind Speed */}
          <Stack direction="vertical" gap={8} align="center">
            <div style={{ fontSize: '28px' }}>💨</div>
            <Text
              style={{
                color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                fontSize: 'var(--ggui-font-size-sm, 14px)',
              }}
            >
              Wind
            </Text>
            <Text
              style={{
                color: 'var(--ggui-color-onSurface, #18181b)',
                fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                fontSize: 'var(--ggui-font-size-lg, 18px)',
              }}
            >
              {windSpeed} {unit === 'C' ? 'km/h' : 'mph'}
            </Text>
          </Stack>
        </Row>

        {/* Divider */}
        <div
          style={{
            height: '1px',
            background: 'var(--ggui-color-outline, #d4d4d8)',
            margin: 'var(--ggui-spacing-2, 8px) 0',
          }}
        />

        {/* 5-Day Forecast */}
        <Stack direction="vertical" gap={12}>
          <Text
            variant="label"
            style={{
              color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
              fontSize: 'var(--ggui-font-size-sm, 14px)',
              fontWeight: 'var(--ggui-font-weight-semibold, 600)',
            }}
          >
            5-Day Forecast
          </Text>

          <Row gap={8} wrap={true} justify="between">
            {forecast.map((item, index) => (
              <div
                key={index}
                style={{
                  flex: '1 1 calc(20% - 7px)',
                  minWidth: '80px',
                  padding: 'var(--ggui-spacing-3, 12px)',
                  background: 'var(--ggui-color-surface, #fafafa)',
                  border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  textAlign: 'center',
                }}
              >
                <Text
                  style={{
                    color: 'var(--ggui-color-onSurface, #18181b)',
                    fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                    fontSize: 'var(--ggui-font-size-sm, 14px)',
                    marginBottom: 'var(--ggui-spacing-1, 4px)',
                  }}
                >
                  {item.day}
                </Text>

                <div
                  style={{
                    fontSize: '24px',
                    margin: 'var(--ggui-spacing-2, 8px) 0',
                  }}
                >
                  {item.icon}
                </div>

                <Stack direction="horizontal" gap={6} justify="center">
                  <Text
                    style={{
                      color: 'var(--ggui-color-onSurface, #18181b)',
                      fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                      fontSize: 'var(--ggui-font-size-sm, 14px)',
                    }}
                  >
                    {item.high}°
                  </Text>
                  <Text
                    style={{
                      color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                      fontSize: 'var(--ggui-font-size-sm, 14px)',
                    }}
                  >
                    {item.low}°
                  </Text>
                </Stack>
              </div>
            ))}
          </Row>
        </Stack>
      </Stack>
    </Card>
  );
}

import { useState, useMemo } from 'react';
import {
  Container,
  Stack,
  Row,
  Card,
  Text,
  Input,
  Button,
  Divider,
  Icon,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface ElementData {
  atomicNumber: number;
  symbol: string;
  name: string;
  atomicWeight: number;
  category: string;
  electronConfiguration: string;
  row: number;
  col: number;
}

interface Props {
  elements: ElementData[];
}

// Category to color mapping using design system tokens
const getCategoryColor = (category: string): { bg: string; text: string; border: string } => {
  const categoryMap: Record<string, { bg: string; text: string; border: string }> = {
    'alkali metals': {
      bg: 'var(--ggui-color-warning-500)',
      text: 'white',
      border: 'var(--ggui-color-warning-600)',
    },
    'alkaline earth metals': {
      bg: 'var(--ggui-color-error-500)',
      text: 'white',
      border: 'var(--ggui-color-error-600)',
    },
    transition: {
      bg: 'var(--ggui-color-primary-500)',
      text: 'white',
      border: 'var(--ggui-color-primary-600)',
    },
    'transition metals': {
      bg: 'var(--ggui-color-primary-500)',
      text: 'white',
      border: 'var(--ggui-color-primary-600)',
    },
    'post-transition metals': {
      bg: 'var(--ggui-color-neutral-400)',
      text: 'var(--ggui-color-onSurface)',
      border: 'var(--ggui-color-neutral-500)',
    },
    metalloids: {
      bg: 'var(--ggui-color-neutral-300)',
      text: 'var(--ggui-color-onSurface)',
      border: 'var(--ggui-color-neutral-500)',
    },
    nonmetals: {
      bg: 'var(--ggui-color-success-500)',
      text: 'white',
      border: 'var(--ggui-color-success-600)',
    },
    'noble gases': {
      bg: 'var(--ggui-color-primary-700)',
      text: 'white',
      border: 'var(--ggui-color-primary-900)',
    },
    halogens: {
      bg: 'var(--ggui-color-primary-300)',
      text: 'var(--ggui-color-onSurface)',
      border: 'var(--ggui-color-primary-500)',
    },
    lanthanides: {
      bg: 'var(--ggui-color-primary-200)',
      text: 'var(--ggui-color-onSurface)',
      border: 'var(--ggui-color-primary-400)',
    },
    actinides: {
      bg: 'var(--ggui-color-primary-100)',
      text: 'var(--ggui-color-onSurface)',
      border: 'var(--ggui-color-primary-300)',
    },
  };

  return categoryMap[category] || {
    bg: 'var(--ggui-color-surfaceVariant)',
    text: 'var(--ggui-color-onSurface)',
    border: 'var(--ggui-color-outline)',
  };
};

export default function GeneratedComponent({ elements }: Props) {
  const { motionEnabled } = useMotion();
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  // Filter elements based on search query
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return elements;

    const query = searchQuery.toLowerCase();
    return elements.filter(
      (el) =>
        el.name.toLowerCase().includes(query) ||
        el.symbol.toLowerCase().includes(query) ||
        el.atomicNumber.toString().includes(query)
    );
  }, [elements, searchQuery]);

  // Get unique categories for legend
  const uniqueCategories = useMemo(() => {
    const categories = new Set(elements.map((el) => el.category));
    return Array.from(categories).sort();
  }, [elements]);

  // Check if element should be visible
  const isElementVisible = (element: ElementData): boolean => {
    return filteredElements.some((el) => el.atomicNumber === element.atomicNumber);
  };

  // Calculate grid layout
  const maxCol = Math.max(...elements.map((el) => el.col), 0);
  const gridColumnsStyle = 'repeat(' + maxCol.toString() + ', 1fr)';

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="full" padding={24}>
        <Stack direction="vertical" gap={24}>
          {/* Header */}
          <div>
            <Text variant="h1">Periodic Table of Elements</Text>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
              Click on any element to view details
            </Text>
          </div>

          {/* Search Input */}
          <Input
            label="Search Elements"
            placeholder="Search by element name, symbol, or atomic number..."
            value={searchQuery}
            onChange={setSearchQuery}
          />

          {/* Legend */}
          <Card padding={16} shadow="sm">
            <Stack direction="vertical" gap={12}>
              <Text variant="h3">Legend</Text>
              <Row gap={16} wrap>
                {uniqueCategories.map((category) => {
                  const colors = getCategoryColor(category);
                  return (
                    <Row key={category} gap={8} align="center">
                      <div
                        style={{
                          width: 24,
                          height: 24,
                          borderRadius: 'var(--ggui-shape-radius-sm)',
                          backgroundColor: colors.bg,
                          borderColor: colors.border,
                          borderWidth: 2,
                          borderStyle: 'solid',
                        }}
                      />
                      <Text variant="body" color="var(--ggui-color-onSurface)">
                        {category}
                      </Text>
                    </Row>
                  );
                })}
              </Row>
            </Stack>
          </Card>

          {/* Main Content - Grid and Detail Panel */}
          <Row gap={24} align="start" wrap={false}>
            {/* Periodic Table Grid */}
            <div style={{ flex: 1, minWidth: 0 }}>
              <Card padding={16} shadow="sm">
                <div
                  style={{
                    display: 'grid',
                    gridTemplateColumns: gridColumnsStyle,
                    gap: 'var(--ggui-spacing-2, 8px)',
                  }}
                >
                  {elements.map((element) => {
                    const isVisible = isElementVisible(element);
                    const colors = getCategoryColor(element.category);

                    return (
                      <div
                        key={element.atomicNumber}
                        style={{
                          gridColumn: element.col,
                          gridRow: element.row,
                          opacity: isVisible ? 1 : 0.2,
                          transition: motionEnabled
                            ? 'opacity 200ms ease-out'
                            : 'none',
                        }}
                      >
                        <button
                          onClick={() => isVisible && setSelectedElement(element)}
                          disabled={!isVisible}
                          style={{
                            width: '100%',
                            padding: 'var(--ggui-spacing-2, 8px)',
                            backgroundColor: colors.bg,
                            color: colors.text,
                            borderColor: colors.border,
                            borderWidth: 2,
                            borderStyle: 'solid',
                            borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                            cursor: isVisible ? 'pointer' : 'not-allowed',
                            fontWeight: 'var(--ggui-font-weight-bold, 700)',
                            fontSize: 'var(--ggui-font-size-sm, 14px)',
                            position: 'relative',
                            minHeight: 64,
                            display: 'flex',
                            flexDirection: 'column',
                            alignItems: 'center',
                            justifyContent: 'center',
                            transition: motionEnabled
                              ? 'transform 150ms ease-out, box-shadow 150ms ease-out'
                              : 'none',
                          }}
                          onMouseEnter={(e) => {
                            if (isVisible) {
                              const target = e.currentTarget as HTMLButtonElement;
                              target.style.transform = 'scale(1.05)';
                              target.style.boxShadow =
                                'var(--ggui-shape-shadow-md)';
                            }
                          }}
                          onMouseLeave={(e) => {
                            const target = e.currentTarget as HTMLButtonElement;
                            target.style.transform = 'scale(1)';
                            target.style.boxShadow = 'none';
                          }}
                        >
                          {/* Atomic number in top-left */}
                          <div
                            style={{
                              position: 'absolute',
                              top: 'var(--ggui-spacing-1, 4px)',
                              left: 'var(--ggui-spacing-1, 4px)',
                              fontSize: 'var(--ggui-font-size-xs, 12px)',
                              fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                            }}
                          >
                            {element.atomicNumber}
                          </div>

                          {/* Symbol centered */}
                          <div
                            style={{
                              fontSize: 'var(--ggui-font-size-lg, 18px)',
                              fontWeight: 'var(--ggui-font-weight-bold, 700)',
                            }}
                          >
                            {element.symbol}
                          </div>

                          {/* Atomic weight small text below */}
                          <div
                            style={{
                              fontSize: 'var(--ggui-font-size-xs, 12px)',
                              fontWeight: 'var(--ggui-font-weight-normal, 400)',
                              opacity: 0.9,
                            }}
                          >
                            {element.atomicWeight.toFixed(2)}
                          </div>
                        </button>
                      </div>
                    );
                  })}
                </div>
              </Card>
            </div>

            {/* Detail Panel */}
            {selectedElement && (
              <div
                style={{
                  width: 320,
                  animation: motionEnabled ? animation.slideInUp : 'none',
                }}
              >
                <Card padding={20} shadow="md">
                  <Stack direction="vertical" gap={16}>
                    <Row justify="between" align="center">
                      <Text variant="h2">{selectedElement.name}</Text>
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => setSelectedElement(null)}
                      >
                        <Icon name="x" size={20} />
                      </Button>
                    </Row>

                    <Divider />

                    {/* Element Symbol and Number */}
                    <div
                      style={{
                        padding: 'var(--ggui-spacing-4, 16px)',
                        backgroundColor: getCategoryColor(
                          selectedElement.category
                        ).bg,
                        color: getCategoryColor(selectedElement.category).text,
                        borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                        textAlign: 'center',
                      }}
                    >
                      <Text
                        variant="h1"
                        color="inherit"
                        weight="bold"
                      >
                        {selectedElement.symbol}
                      </Text>
                      <Text
                        variant="body"
                        color="inherit"
                        weight="medium"
                      >
                        Atomic Number: {selectedElement.atomicNumber}
                      </Text>
                    </div>

                    {/* Details */}
                    <Stack direction="vertical" gap={12}>
                      <div>
                        <Text
                          variant="label"
                          weight="semibold"
                          color="var(--ggui-color-onSurfaceVariant)"
                        >
                          Atomic Weight
                        </Text>
                        <Text variant="body" color="var(--ggui-color-onSurface)">
                          {selectedElement.atomicWeight.toFixed(4)}
                        </Text>
                      </div>

                      <div>
                        <Text
                          variant="label"
                          weight="semibold"
                          color="var(--ggui-color-onSurfaceVariant)"
                        >
                          Category
                        </Text>
                        <Text variant="body" color="var(--ggui-color-onSurface)">
                          {selectedElement.category}
                        </Text>
                      </div>

                      <div>
                        <Text
                          variant="label"
                          weight="semibold"
                          color="var(--ggui-color-onSurfaceVariant)"
                        >
                          Electron Configuration
                        </Text>
                        <Text
                          variant="body"
                          color="var(--ggui-color-onSurface)"
                          style={{
                            fontFamily: 'monospace',
                            wordBreak: 'break-word',
                            fontSize: 'var(--ggui-font-size-sm, 14px)',
                          }}
                        >
                          {selectedElement.electronConfiguration}
                        </Text>
                      </div>

                      <div>
                        <Text
                          variant="label"
                          weight="semibold"
                          color="var(--ggui-color-onSurfaceVariant)"
                        >
                          Position
                        </Text>
                        <Text variant="body" color="var(--ggui-color-onSurface)">
                          Row {selectedElement.row}, Column {selectedElement.col}
                        </Text>
                      </div>
                    </Stack>
                  </Stack>
                </Card>
              </div>
            )}
          </Row>

          {/* No Results Message */}
          {filteredElements.length === 0 && (
            <Card padding={24} shadow="sm">
              <Stack direction="vertical" gap={12} align="center">
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                  No elements found matching "{searchQuery}"
                </Text>
              </Stack>
            </Card>
          )}

          {/* Results Count */}
          {searchQuery && filteredElements.length > 0 && (
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant)"
            >
              Showing {filteredElements.length} of {elements.length} elements
            </Text>
          )}
        </Stack>
      </Container>
    </>
  );
}
